const httpResp = $input.first().json;
const brandData = $('Build Presentation Data from Pipeline').first().json;

let slideContent = {};
try {
  const text = httpResp.content[0].text;
  const clean = text.replace(/```json|```/g, '').trim();
  slideContent = JSON.parse(clean);
} catch(e) {
  slideContent = {
    executiveSummary: 'Presentation content generation pending manual review.',
    valueProposition: 'TBD',
    competitiveAdvantage: 'TBD',
    roadshowStrategy: 'TBD',
    seasonalStrategy: { q3: 'TBD', q4: 'TBD', q1: 'TBD', q2: 'TBD' },
    staffingRecommendation: 'TBD',
    riskFactors: 'TBD'
  };
}

// Build the full presentation document as formatted text
// This will be saved as a Google Doc in the brand folder
const docContent = `ROADSHOW 2026 PRESENTATION
${brandData.brandName}
${'='.repeat(50)}

Prepared by Ascenda Group | Sam's Club Roadshow Partner
Contact: ${brandData.contactName} | ${brandData.email} | ${brandData.phone}

${'─'.repeat(50)}
EXECUTIVE SUMMARY
${'─'.repeat(50)}
${slideContent.executiveSummary}

${'─'.repeat(50)}
COMPANY & CATEGORY OVERVIEW
${'─'.repeat(50)}
Company: ${brandData.brandName}
Category: ${brandData.category}
Product: ${brandData.productName}
Revenue Tier: ${brandData.revenue}
Target Retailer: ${brandData.retailer}
Pipeline Score: ${brandData.score}/100
Readiness Score: ${brandData.readinessScore}/100

Product Description:
${brandData.productDescription}

Differentiation:
${brandData.differentiation}

${'─'.repeat(50)}
VALUE PROPOSITION FOR SAM'S CLUB MEMBERS
${'─'.repeat(50)}
${slideContent.valueProposition}

Member Value Statement:
${brandData.memberValue}

20% Value Advantage: ${brandData.has20PctValue === 'yes' ? 'CONFIRMED' : 'Under Review'}
Consignment Ready: ${brandData.consignmentReady === 'yes' ? 'YES' : 'No'}
Multi-Club Capable: ${brandData.multiClub === 'yes' ? 'YES' : 'No'}

${'─'.repeat(50)}
COMPETITIVE ADVANTAGE
${'─'.repeat(50)}
${slideContent.competitiveAdvantage}

Key Competitors: ${brandData.competitors}

${'─'.repeat(50)}
ROADSHOW EVENT DETAILS
${'─'.repeat(50)}
Show Length: ${brandData.recommendedShowLength}
Club Reach: ${brandData.recommendedClubCount} clubs
Format: Category 63 Pop-Up Shop / Roadshow
Model: ${brandData.consignmentReady === 'yes' ? 'Consignment' : 'Standard'}

Strategy:
${slideContent.roadshowStrategy}

Staffing:
${slideContent.staffingRecommendation}

${'─'.repeat(50)}
FINANCIAL PROJECTIONS
${'─'.repeat(50)}
Sam's Club Price: $${brandData.samsPrice || 'TBD'}
Landed Cost: $${brandData.landedCost || 'TBD'}
Gross Margin: ${brandData.grossMarginPct || brandData.vendorMargin || 'TBD'}%
Revenue Per Event: $${brandData.revenuePerEvent || 'TBD'}
Units Per Event: ${brandData.projectedUnitsPerEvent || 'TBD'}
Break-Even Events: ${brandData.breakEvenEvents || 'TBD'}
Year 1 Projection: $${brandData.year1Projection ? (brandData.year1Projection / 1000000).toFixed(1) + 'M' : 'TBD'}
Year 2 Projection: $${brandData.year2Projection ? (brandData.year2Projection / 1000000).toFixed(1) + 'M' : 'TBD'}
ROI: ${brandData.roi || 'TBD'}%

${'─'.repeat(50)}
ITEM DETAILS
${'─'.repeat(50)}
Item: ${brandData.productName}
MSRP: $${brandData.msrp || 'TBD'}
Sam's Price: $${brandData.samsPrice || 'TBD'}
Cost: $${brandData.landedCost || 'TBD'}
Margin: ${brandData.vendorMargin || 'TBD'}%

${'─'.repeat(50)}
2026 SEASONAL ROADSHOW PLAN
${'─'.repeat(50)}
Q3 (Aug-Oct): ${slideContent.seasonalStrategy.q3}
Q4 (Nov-Jan): ${slideContent.seasonalStrategy.q4}
Q1 (Feb-Apr): ${slideContent.seasonalStrategy.q1}
Q2 (May-Jul): ${slideContent.seasonalStrategy.q2}

${'─'.repeat(50)}
RISK FACTORS
${'─'.repeat(50)}
${slideContent.riskFactors}

${'─'.repeat(50)}
Prepared by Ascenda Group
Sam's Club & Costco Retail Readiness
${new Date().toISOString().split('T')[0]}
`;

return [{ json: { ...brandData, slideContent, docContent, presentationGeneratedAt: new Date().toISOString() } }];
